--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3324,6 +3324,73 @@ Value *InstCombinerImpl::matchSelectFromAndOr(Value *A, Value *B, Value *C,
   return nullptr;
 }

+/// Fold (icmp Pred1 X, C1) op (icmp Pred2 (X & Mask), C2) when the
+/// masked comparison implies the other comparison.
+/// For AND: if icmp2 implies icmp1, result is icmp2
+/// For OR:  if icmp2 implies icmp1, result is icmp1
+static Value *foldAndOrOfICmpWithMaskedICmp(ICmpInst *Cmp0, ICmpInst *Cmp1,
+                                            bool IsAnd, bool IsLogical,
+                                            InstCombiner::BuilderTy &Builder,
+                                            const SimplifyQuery &Q) {
+  // Match Cmp0: icmp Pred0 X, C0
+  CmpPredicate Pred0;
+  Value *X;
+  const APInt *C0;
+  if (!match(Cmp0, m_ICmp(Pred0, m_Value(X), m_APInt(C0))))
+    return nullptr;
+
+  // Match Cmp1: icmp Pred1 (X & Mask), C1
+  CmpPredicate Pred1;
+  Value *Masked;
+  const APInt *C1, *Mask;
+  if (!match(Cmp1, m_ICmp(Pred1, m_Value(Masked), m_APInt(C1))))
+    return nullptr;
+
+  if (!match(Masked, m_c_And(m_Specific(X), m_APInt(Mask))))
+    return nullptr;
+
+  // For now, only handle EQ/NE for the masked comparison
+  if (Pred1 != ICmpInst::ICMP_EQ && Pred1 != ICmpInst::ICMP_NE)
+    return nullptr;
+
+  // Check if the masked comparison defines a contiguous range for X.
+  // This happens when ~Mask has contiguous low bits (a mask).
+  APInt FreeBits = ~(*Mask);
+  if (!FreeBits.isMask())
+    return nullptr;
+
+  // For EQ: (X & Mask) == C1 is only satisfiable if C1 & ~Mask == 0
+  // For NE: (X & Mask) != C1 is always true if C1 & ~Mask != 0
+  if ((*C1 & FreeBits) != 0)
+    return nullptr;
+
+  // Compute the range of X satisfying the masked comparison.
+  // Since FreeBits is a contiguous block of low bits,
+  // (X & Mask) == C1 means X is in [C1, C1 | FreeBits + 1)
+  // (X & Mask) != C1 means X is NOT in [C1, C1 | FreeBits + 1)
+  APInt Low = *C1;
+  APInt High = *C1 | FreeBits;
+  ++High;
+  ConstantRange MaskedRange =
+      Pred1 == ICmpInst::ICMP_EQ
+          ? ConstantRange(Low, High)
+          : ConstantRange(Low, High).inverse();
+
+  // Compute the range of X satisfying the other comparison.
+  ConstantRange OtherRange = ConstantRange::makeExactICmpRegion(Pred0, *C0);
+
+  // Check if the masked comparison implies the other comparison.
+  // i.e., all values satisfying icmp1 also satisfy icmp0.
+  if (!OtherRange.contains(MaskedRange))
+    return nullptr;
+
+  // For AND: if icmp1 (masked) implies icmp0, result is icmp1
+  // For OR:  if icmp1 (masked) implies icmp0, result is icmp0
+  if (IsAnd)
+    return Cmp1;
+  return Cmp0;
+}
+
 // (icmp eq X, C) | (icmp ult Other, (X - C)) -> (icmp ule Other, (X - (C + 1)))
 // (icmp ne X, C) & (icmp uge Other, (X - C)) -> (icmp ugt Other, (X - (C + 1)))
 static Value *foldAndOrOfICmpEqConstantAndICmp(ICmpInst *LHS, ICmpInst *RHS,
@@ -3408,6 +3475,11 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
                                                   /*IsLogical*/ false, Builder))
     return V;

+  if (Value *V = foldAndOrOfICmpWithMaskedICmp(LHS, RHS, IsAnd, IsLogical, Builder, Q))
+    return V;
+  if (Value *V = foldAndOrOfICmpWithMaskedICmp(RHS, LHS, IsAnd, IsLogical, Builder, Q))
+    return V;
+
   if (Value *V =
           foldAndOrOfICmpsWithConstEq(LHS, RHS, IsAnd, IsLogical, Builder, Q))
     return V;

